def range_summary(nums):
    if not nums:
        return ''

    runs = []
    current, start = None, None
    for num in sorted(set(nums)):
        if current is not None and current + 1 == num:
            runs[-1][1] = num
        else:
            runs.append([current, num])
            current = num
    else:
        runs.append([current])

    result = ', '.join(f'{start}-{end}' if end > start else str(start) for start, end in runs)
    return result
